/* Variable Declaration and Initialization in C */
#include <stdio.h>
int main() {
    int age;           // Declaration only
    int marks = 95;    // Declaration + Initialization
    float gpa = 8.7;   // float variable
    char grade = 'A';  // char variable
    int x = 10, y = 20, z = 30;  // Multiple declaration

    printf("Age: %d\n", age);    // Garbage value (uninitialized)
    printf("Marks: %d\n", marks);
    printf("GPA: %.1f\n", gpa);
    printf("Grade: %c\n", grade);
    return 0;
}

/* Function Syntax in C */
#include <stdio.h>

// Function Prototype (Declaration)
int add(int a, int b);

// Function Definition
int add(int a, int b) {
    return a + b;    // returns sum
}

int main() {
    int result = add(10, 20);  // Function Call
    printf("Sum = %d\n", result);
    // Output: Sum = 30
    return 0;
}

