/* I/O in C */
#include <stdio.h>

int main() {
    int age;
    float salary;
    char name[50];

    printf("Enter name: ");
    scanf("%s", name);
    printf("Enter age: ");
    scanf("%d", &age);     // & = address-of operator
    printf("Enter salary: ");
    scanf("%f", &salary);

    printf("Name: %s\n", name);
    printf("Age: %d\tSalary: %.2f\n", age, salary);
    return 0;
}

/* Integer Data Types in C */
#include <stdio.h>
#include <limits.h>

int main() {
    short s = 32767;       // 2 bytes
    int i = 2147483647;    // 4 bytes (INT_MAX)
    long l = 2147483647L;  // suffix L
    long long ll = 9223372036854775807LL; // suffix LL
    unsigned int u = 4294967295U; // suffix U

    int hex = 0xFF;   // prefix 0x = hexadecimal (255)
    int oct = 0777;   // prefix 0  = octal (511)
    int bin = 0b1010; // prefix 0b = binary (C23, GCC ext)

    printf("short: %d\nint: %d\nlong: %ld\n", s, i, l);
    printf("hex: %d, oct: %o, hex-print: %x\n", hex, oct, hex);
    return 0;
}

/* Floating-Point Data Types */
#include <stdio.h>

int main() {
    float  f  = 3.14f;         // f suffix = float literal
    double d  = 3.14159265358979; // default is double
    long double ld = 3.14159265358979323L; // L suffix

    printf("float:       %.7f\n", f);   // precision limit visible
    printf("double:      %.15f\n", d);
    printf("long double: %.19Lf\n", ld);

    // Scientific notation
    double sci = 1.5e4;   // 1.5 x 10^4 = 15000
    double neg = 2.5e-3;  // 2.5 x 10^-3 = 0.0025
    printf("sci: %g, neg: %g\n", sci, neg);
    return 0;
}

/* Character Data Type in C */
#include <stdio.h>

int main() {
    char c1 = 'A';       // character literal
    char c2 = 65;        // same as 'A' (ASCII value)
    char c3 = '\n';      // escape sequence

    printf("%c = %d\n", c1, c1); // A = 65
    printf("%c = %d\n", c2, c2); // A = 65

    // Arithmetic on chars
    char lower = c1 + 32; // 'A' + 32 = 'a'
    printf("%c\n", lower); // a

    // Input methods
    char input;
    scanf(" %c", &input);  // space before %c skips whitespace
    char input2 = getchar(); // reads single character
    return 0;
}

/* Type Casting in C */
#include <stdio.h>

int main() {
    // Implicit casting (promotion)
    int i = 10;
    float f = i;       // int → float automatically
    printf("%f\n", f); // 10.000000

    // Explicit casting (truncation NOT rounding)
    float pi = 3.99;
    int trunc = (int)pi;  // 3, NOT 4
    printf("%d\n", trunc); // 3

    // Integer division vs float division
    printf("%d\n", 7/2);         // 3 (integer division)
    printf("%f\n", 7/(float)2);  // 3.500000

    // Overflow wraparound
    unsigned char uc = 255;
    uc = uc + 1;  // wraps to 0
    printf("%d\n", uc); // 0
    return 0;
}

/* Operators in C */
#include <stdio.h>

int main() {
    // Pre vs Post increment
    int a = 5;
    printf("%d\n", ++a); // 6 (increment then print)
    printf("%d\n", a++); // 6 (print then increment)
    printf("%d\n", a);   // 7

    // Bitwise operators
    int x = 0b1010; // 10
    int y = 0b1100; // 12
    printf("AND: %d\n", x & y);  // 0b1000 = 8
    printf("OR:  %d\n", x | y);  // 0b1110 = 14
    printf("XOR: %d\n", x ^ y);  // 0b0110 = 6
    printf("NOT: %d\n", ~x);     // -11 (two's complement)

    // Bit manipulation
    int n = 5;          // 0b0101
    int i = 1;
    n = n | (1 << i);   // Set bit i:   0b0111 = 7
    n = n & ~(1 << i);  // Unset bit i: 0b0101 = 5
    n = n ^ (1 << i);   // Flip bit i:  0b0111 = 7
    int check = (n >> i) & 1; // Check bit i: 1 or 0
    printf("check: %d\n", check);
    return 0;
}

/* Control Constructs in C */
#include <stdio.h>

int main() {
    int marks = 75;

    // if-else-if ladder
    if (marks >= 90)       printf("Grade: A+\n");
    else if (marks >= 75)  printf("Grade: A\n");   // prints this
    else if (marks >= 60)  printf("Grade: B\n");
    else                   printf("Grade: F\n");

    // Ternary operator
    char *result = (marks >= 40) ? "Pass" : "Fail";
    printf("%s\n", result); // Pass

    // Switch statement
    int day = 3;
    switch(day) {
        case 1: printf("Monday\n");    break;
        case 2: printf("Tuesday\n");   break;
        case 3: printf("Wednesday\n"); break; // prints this
        default: printf("Weekend\n");
    }
    return 0;
}

/* Loops in C — All 3 types */
#include <stdio.h>

int main() {
    // for loop — print 1 to 5
    for (int i = 1; i <= 5; i++)
        printf("%d ", i);   // 1 2 3 4 5
    printf("\n");

    // while loop — same output
    int i = 1;
    while (i <= 5) {
        printf("%d ", i++);
    }
    printf("\n");

    // do-while — executes at least once
    int j = 10;
    do {
        printf("%d\n", j); // prints 10 even though condition false after
    } while (j < 5);

    // Star pattern (right triangle)
    for (int r = 1; r <= 4; r++) {
        for (int c = 1; c <= r; c++)
            printf("* ");
        printf("\n");
    }
    return 0;
}

/* Jump Statements in C */
#include <stdio.h>

int main() {
    // break — exit loop early
    for (int i = 1; i <= 10; i++) {
        if (i == 5) break;
        printf("%d ", i);   // 1 2 3 4
    }
    printf("\n");

    // continue — skip iteration
    for (int i = 1; i <= 10; i++) {
        if (i % 2 == 0) continue; // skip even numbers
        printf("%d ", i);  // 1 3 5 7 9
    }
    printf("\n");

    // goto (use sparingly)
    int x = 0;
    loop:
        printf("%d ", x++);
        if (x < 5) goto loop;   // 0 1 2 3 4
    printf("\n");

    return 0; // exits main(), returns 0 to OS
}

/* Functions in C — Pass by Value vs Address */
#include <stdio.h>

// Pass by VALUE — original unchanged
void doubleByValue(int x) {
    x = x * 2;  // only local copy changes
}

// Pass by ADDRESS — original changes
void doubleByAddress(int *x) {
    *x = *x * 2;  // dereference and modify original
}

// Recursion — factorial
int factorial(int n) {
    if (n == 0) return 1;         // base case
    return n * factorial(n - 1);  // recursive case
}

int main() {
    int a = 5;
    doubleByValue(a);
    printf("%d\n", a);   // 5 (unchanged)

    doubleByAddress(&a);
    printf("%d\n", a);   // 10 (changed!)

    printf("%d\n", factorial(5)); // 120
    return 0;
}

/* Arrays in C */
#include <stdio.h>

int main() {
    // 1D array
    int arr[5] = {10, 20, 30, 40, 50};
    printf("%d\n", arr[2]);  // 30

    // 2D array (3x3 matrix)
    int mat[3][3] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };
    // Print matrix
    for (int r = 0; r < 3; r++) {
        for (int c = 0; c < 3; c++)
            printf("%d ", mat[r][c]);
        printf("\n");
    }

    // Jagged array (array of pointers)
    int a[] = {1, 2};
    int b[] = {3, 4, 5};
    int *jagged[] = {a, b};  // rows of different lengths
    printf("%d\n", jagged[1][2]);  // 5
    return 0;
}

/* Pointers and Dynamic Memory */
#include <stdio.h>
#include <stdlib.h>

int main() {
    int x = 42;
    int *ptr = &x;       // ptr stores address of x

    printf("Value: %d\n", *ptr);    // 42 (dereference)
    printf("Address: %p\n", ptr);   // memory address

    *ptr = 100;          // changes x through pointer
    printf("%d\n", x);  // 100

    // Pointer arithmetic
    int arr[] = {10, 20, 30};
    int *p = arr;        // points to arr[0]
    printf("%d\n", *(p+1)); // 20 (arr[1])
    printf("%d\n", *(p+2)); // 30 (arr[2])

    // Dynamic Memory Allocation
    int n = 5;
    int *dyn = (int*)malloc(n * sizeof(int));
    if (dyn == NULL) { printf("Alloc failed\n"); return 1; }
    for (int i = 0; i < n; i++) dyn[i] = i * 10;
    for (int i = 0; i < n; i++) printf("%d ", dyn[i]);
    // Output: 0 10 20 30 40
    free(dyn);  // ALWAYS free heap memory
    return 0;
}

/* Strings in C */
#include <stdio.h>
#include <string.h>

int main() {
    // 3 ways to declare strings
    char s1[] = "Hello";          // array (modifiable)
    char *s2 = "World";           // string literal (read-only)
    char s3[10];

    // String functions
    printf("%lu\n", strlen(s1));     // 5 (not counting \0)
    strcpy(s3, s1);                  // copy s1 into s3
    strcat(s3, " World");            // s3 = "Hello World"
    printf("%s\n", s3);             // Hello World
    printf("%d\n", strcmp(s1,"Hello")); // 0 (equal)

    // Manual string traversal
    for (int i = 0; s1[i] != '\0'; i++)
        printf("%c", s1[i]);
    printf("\n");
    return 0;
}

/* Preprocessor Directives in C */
#include <stdio.h>

#define PI 3.14159    // macro constant
#define SQUARE(x) ((x)*(x))  // function-like macro
#define DEBUG 1       // flag for conditional compilation

typedef unsigned long int ULONG;  // type alias

int main() {
    float area = PI * SQUARE(5);  // expands before compile
    printf("Area: %.2f\n", area);  // 78.54

    ULONG big = 1000000UL;
    printf("%lu\n", big);

    // Conditional compilation
    #ifdef DEBUG
        printf("[DEBUG] area = %f\n", area);
    #endif

    const int MAX = 100;  // const: value cannot change
    // MAX = 200;  // ERROR: assignment of read-only variable
    return 0;
}

/* Structures in C */
#include <stdio.h>
#include <string.h>

// Structure definition
struct Student {
    int rollNo;
    char name[50];
    float gpa;
};

void printStudent(struct Student *s) {
    printf("Roll: %d, Name: %s, GPA: %.2f\n",
           s->rollNo, s->name, s->gpa);
}

int main() {
    struct Student s1;
    s1.rollNo = 101;
    strcpy(s1.name, "Alice");
    s1.gpa = 9.2;

    printStudent(&s1);  // Roll: 101, Name: Alice, GPA: 9.20

    printf("Size: %lu bytes\n", sizeof(struct Student)); // may include padding
    return 0;
}

/* Unions and Enums in C */
#include <stdio.h>

// Union — shared memory
union Data {
    int i;
    float f;
    char c;
};

// Enum — named constants
enum Day { MON=1, TUE, WED, THU, FRI, SAT, SUN };

int main() {
    union Data d;
    d.i = 65;
    printf("int: %d\n", d.i);    // 65
    printf("char: %c\n", d.c);   // A (same memory!)

    d.f = 3.14;  // now float is valid, i and c have garbage
    printf("float: %.2f\n", d.f); // 3.14

    enum Day today = WED;
    if (today == WED)
        printf("Midweek!\n"); // prints this
    printf("Day number: %d\n", today); // 3
    return 0;
}

/* File Handling in C */
#include <stdio.h>

int main() {
    // Writing to a file
    FILE *fp = fopen("data.txt", "w");
    if (fp == NULL) {
        printf("Error opening file\n");
        return 1;
    }
    fprintf(fp, "Name: Alice\nMarks: 95\n");
    fclose(fp);  // MUST close

    // Reading from a file
    fp = fopen("data.txt", "r");
    char line[100];
    while (fgets(line, sizeof(line), fp) != NULL)
        printf("%s", line);  // prints file contents
    fclose(fp);

    return 0;
}

/* C++ Fundamentals */
#include <iostream>
#include <iomanip>
#include <vector>
#include <stack>
#include <map>
using namespace std;

int main() {
    // C++ I/O
    int age;
    cout << "Enter age: ";
    cin >> age;
    cout << "Age: " << age << endl;

    // Manipulators
    double pi = 3.14159;
    cout << fixed << setprecision(2) << pi << endl; // 3.14
    cout << setw(10) << "Hello" << endl;            //      Hello

    // STL Vector
    vector<int> v = {10, 20, 30};
    v.push_back(40);
    for (int x : v) cout << x << " ";  // 10 20 30 40
    cout << endl;

    // STL Map
    map<string, int> marks;
    marks["Alice"] = 95;
    marks["Bob"]   = 88;
    cout << marks["Alice"] << endl;  // 95

    return 0;
}
